def count_within_depth(spec: dict) -> int:
    """Count nodes whose BFS depth from start is at most the limit."""
    adj = spec["adj"]; start = spec["start"]; limit = spec["depth"]
    depth = {start: 0}; queue = [start]; i = 0
    while i < len(queue):
        n = queue[i]; i += 1
        if depth[n] < limit:
            for t in adj.get(n, []):
                if t not in depth:
                    depth[t] = depth[n] + 1
                    queue.append(t)
    return len(depth)

