def can_reach(spec: dict) -> bool:
    """Return True if target can be reached from start along directed edges."""
    target = spec["target"]
    adj = {}
    for u, v in spec["edges"]:
        adj.setdefault(u, []).append(v)
    seen = set()
    stack = [spec["start"]]
    while stack:
        n = stack.pop()
        if n in seen:
            continue
        seen.add(n)
        if n == target:
            return True
        stack.extend(adj.get(n, []))
    return False

