def first_leaf_name(spec: dict) -> str:
    """Breadth-first from the root of a parent map, return the first childless node."""
    parent = spec["parent"]; root = spec["root"]
    children = {}
    for c, p in parent.items():
        children.setdefault(p, []).append(c)
    seen = set(); queue = [root]; i = 0
    while i < len(queue):
        n = queue[i]; i += 1
        if n in seen:
            continue
        seen.add(n)
        kids = children.get(n, [])
        if not kids:
            return n
        queue.extend(kids)
    return "none"

