def frontier_size(spec: dict) -> int:
    """Count nodes sitting exactly 'depth' hops from start."""
    adj = spec["adj"]; start = spec["start"]; d = spec["depth"]
    depth = {start: 0}; queue = [start]; i = 0; count = 0
    while i < len(queue):
        n = queue[i]; i += 1
        if depth[n] == d:
            count += 1
        elif depth[n] < d:
            for t in adj.get(n, []):
                if t not in depth:
                    depth[t] = depth[n] + 1
                    queue.append(t)
    return count

