def bounded_leaf_names(spec: dict) -> list:
    """Sorted names of dead-end nodes found at most 'depth' hops from start."""
    adj = spec["adj"]; start = spec["start"]; cap = spec["depth"]
    depth = {start: 0}; queue = [start]; i = 0; leaves = []
    while i < len(queue):
        n = queue[i]; i += 1
        if not adj.get(n, []):
            leaves.append(n)
